sp_angular_provider.script:
// Use this function to convert a string of HTML tags to a simplie string
// For example, given the following string, get the first 5 readable characters
// var testHtml = '<p><img style="max-width: 100%; max-height: 480px;" src="/sys_attachment.do?sys_id=1d5b01bc1b7c7410888aebde6e4bcbb2" /></p>
// <p>DTech Apps on ServiceNow</p>'
// var converted = htmlToStringService.convertHtmlToString(testHtml); // output: DTech Apps on ServiceNow
// var result = converted.substring(0, 5); // output: DTech
function htmlToStringService() {
    return {
        convertHtmlToString: function(someHtmlText) {
            var divElement = document.createElement('div');
            divElement.innerHTML = someHtmlText;

            return divElement.textContent || divElement.innerHTML || '';
        }
    };
}
